'use client';

import { useState } from 'react';
import { signIn } from 'next-auth/react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { Mail, Lock, Loader2, ChevronRight, Fingerprint } from 'lucide-react';

export default function LoginPage() {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const router = useRouter();

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);
        setError('');

        try {
            const res = await signIn('credentials', {
                email,
                password,
                redirect: false,
            });

            if (res?.error) {
                setError('Authentication failed. Check your credentials.');
            } else {
                router.push('/dashboard');
            }
        } catch (err: unknown) {
            setError(err instanceof Error ? err.message : 'System error. Please retry shortly.');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-background p-6 relative overflow-hidden">
            {/* Background elements */}
            <div className="absolute top-0 right-0 w-96 h-96 bg-primary/5 rounded-full blur-[100px] -mr-48 -mt-48" />
            <div className="absolute bottom-0 left-0 w-96 h-96 bg-indigo-500/5 rounded-full blur-[100px] -ml-48 -mb-48" />

            <div className="w-full max-w-[440px] relative z-10 animate-in fade-in slide-in-from-bottom-8 duration-1000">
                <div className="flex flex-col items-center mb-12">
                    <Link href="/" className="mb-10 group transition-transform hover:scale-110 active:scale-95">
                        <div className="relative">
                            <div className="absolute -inset-4 bg-primary/10 rounded-full blur-2xl group-hover:bg-primary/20 transition-all" />
                            <div className="relative w-16 h-16 bg-foreground text-background rounded-2xl flex items-center justify-center font-black text-xl shadow-2xl">
                                D2C
                            </div>
                        </div>
                    </Link>
                    <h1 className="text-4xl font-black tracking-tighter text-foreground mb-3 text-center">
                        Welcome to <span className="text-primary">Draw2Code</span>
                    </h1>
                    <p className="text-muted-foreground font-bold tracking-[0.2em] uppercase text-[10px] text-center">
                        The intersection of design and code
                    </p>
                </div>

                <div className="bg-card/50 backdrop-blur-3xl rounded-[40px] border border-border/50 p-10 shadow-2xl">
                    {error && (
                        <div className="mb-8 p-4 bg-destructive/10 border border-destructive/20 text-destructive rounded-2xl text-[10px] font-black uppercase tracking-widest text-center animate-in shake duration-500">
                            {error}
                        </div>
                    )}

                    <form onSubmit={handleSubmit} className="space-y-8">
                        <div className="space-y-3 group">
                            <label className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground/60 ml-1 group-focus-within:text-primary transition-colors">Workspace Access</label>
                            <div className="relative">
                                <Mail className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-muted-foreground/40 group-focus-within:text-primary transition-colors" />
                                <input
                                    type="email"
                                    value={email}
                                    onChange={(e) => setEmail(e.target.value)}
                                    className="w-full pl-14 pr-7 h-16 rounded-2xl border-2 border-border/50 bg-background/50 outline-none focus:border-primary focus:ring-4 focus:ring-primary/5 transition-all text-sm font-semibold"
                                    placeholder="your@email.com"
                                    required
                                />
                            </div>
                        </div>

                        <div className="space-y-3 group">
                            <div className="flex justify-between items-center ml-1">
                                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-muted-foreground/60 group-focus-within:text-primary transition-colors">Security Key</label>
                                <button type="button" className="text-[10px] font-black uppercase tracking-[0.2em] text-primary hover:underline">Reset</button>
                            </div>
                            <div className="relative">
                                <Lock className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-muted-foreground/40 group-focus-within:text-primary transition-colors" />
                                <input
                                    type="password"
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                    className="w-full pl-14 pr-7 h-16 rounded-2xl border-2 border-border/50 bg-background/50 outline-none focus:border-primary focus:ring-4 focus:ring-primary/5 transition-all text-sm font-semibold"
                                    placeholder="••••••••"
                                    required
                                />
                            </div>
                        </div>

                        <button
                            type="submit"
                            disabled={isLoading}
                            className="w-full h-18 bg-foreground text-background rounded-2xl font-black text-sm uppercase tracking-[0.2em] shadow-2xl hover:bg-foreground/90 hover:-translate-y-1 shadow-foreground/10 transition-all active:scale-95 disabled:opacity-50 flex items-center justify-center gap-3"
                        >
                            {isLoading ? (
                                <Loader2 className="w-6 h-6 animate-spin" />
                            ) : (
                                <>
                                    Log into Lab
                                    <Fingerprint className="w-5 h-5 opacity-40" />
                                </>
                            )}
                        </button>
                    </form>

                    <div className="mt-12 pt-10 border-t border-border/50 text-center">
                        <p className="text-sm text-muted-foreground/60 font-medium">
                            Don&apos;t have access? {' '}
                            <Link href="/signup" className="text-foreground font-black hover:text-primary transition-colors">
                                Create Identity
                            </Link>
                        </p>
                    </div>
                </div>

                <p className="mt-12 text-center text-[10px] text-muted-foreground/40 font-black tracking-widest uppercase">
                    Secure Biometric-Grade Access Controller v1.0
                </p>
            </div>

            <style jsx>{`
                .h-18 { height: 4.5rem; }
            `}</style>
        </div>
    );
}

'use client';

import { useSearchParams } from 'next/navigation';
import { Suspense, useState, useEffect } from 'react';

function PreviewContent() {
    const searchParams = useSearchParams();
    const codeId = searchParams.get('id');
    const encodedCode = searchParams.get('code');
    const [html, setHtml] = useState<string | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        async function fetchCode() {
            if (codeId) {
                try {
                    const res = await fetch(`/api/code?id=${codeId}`);
                    if (!res.ok) {
                        throw new Error('Failed to fetch code');
                    }
                    const data = await res.json();
                    setHtml(data.code);
                } catch (err) {
                    console.error('Error fetching code:', err);
                    setError('Failed to load preview');
                } finally {
                    setLoading(false);
                }
            } else if (encodedCode) {
                try {
                    const decodedCode = decodeURIComponent(atob(encodedCode));
                    setHtml(decodedCode);
                } catch (err) {
                    console.error('Error decoding code:', err);
                    setError('Failed to decode preview');
                } finally {
                    setLoading(false);
                }
            } else {
                setError('No code provided');
                setLoading(false);
            }
        }

        fetchCode();
    }, [codeId, encodedCode]);

    if (loading) {
        return (
            <div className="flex items-center justify-center h-screen bg-background">
                <div className="flex flex-col items-center gap-4">
                    <div className="w-10 h-10 border-4 border-primary/20 border-t-primary rounded-full animate-spin" />
                    <p className="text-sm font-medium text-muted-foreground animate-pulse uppercase tracking-widest">Compiling Preview...</p>
                </div>
            </div>
        );
    }

    if (error || !html) {
        return (
            <div className="flex items-center justify-center h-screen bg-background">
                <div className="text-center p-8 bg-card rounded-3xl border border-border shadow-2xl">
                    <h1 className="text-3xl font-black text-foreground mb-4 italic-title">
                        {error || 'No Code Found'}
                    </h1>
                    <p className="text-muted-foreground max-w-xs mx-auto text-sm">We couldn't retrieve the code for this preview. It may have been deleted or expired.</p>
                </div>
            </div>
        );
    }

    return (
        <div className="w-full h-screen bg-white">
            <iframe
                srcDoc={html}
                className="w-full h-full border-none"
                title="Generated App Preview"
                sandbox="allow-scripts allow-same-origin allow-forms allow-popups allow-modals"
            />
        </div>
    );
}

export default function PreviewPage() {
    return (
        <Suspense fallback={
            <div className="flex items-center justify-center h-screen bg-background">
                <div className="w-10 h-10 border-4 border-primary/20 border-t-primary rounded-full animate-spin" />
            </div>
        }>
            <PreviewContent />
        </Suspense>
    );
}

'use client';

import { useState, useRef, useEffect } from 'react';
import dynamic from 'next/dynamic';
import { Save, Layout, MessageSquare, Mic, Settings, X, ChevronLeft, Undo2, Redo2, Loader2 } from 'lucide-react';
import { useParams, useRouter } from 'next/navigation';
import { cn } from '@/lib/utils';
import type { CanvasBoardRef } from '@/components/editor/CanvasBoard';
import type { SupabaseConfig, CustomApiConfig } from '@/lib/ai-generator';

// Dynamic import for CanvasBoard to avoid SSR issues with tldraw
const CanvasBoard = dynamic(() => import('@/components/editor/CanvasBoard'), { ssr: false });
const ChatSidebar = dynamic(() => import('@/components/editor/ChatSidebar'), { ssr: false });

interface ChatMessage {
    id: string;
    role: 'user' | 'assistant';
    content: string;
    timestamp: Date;
}

export default function ProjectWorkspace() {
    const params = useParams();
    const router = useRouter();
    const projectId = params.id as string;
    const canvasRef = useRef<CanvasBoardRef>(null);

    const [projectName, setProjectName] = useState('Loading...');
    const [prompt, setPrompt] = useState('');
    const [isGenerating, setIsGenerating] = useState(false);
    const [language, setLanguage] = useState('typescript');
    const [framework, setFramework] = useState('react');
    const [isLoading, setIsLoading] = useState(true);
    const [initialCanvasData, setInitialCanvasData] = useState<unknown>(null);

    // State for settings modal
    const [showSettings, setShowSettings] = useState(false);
    const [activeSettingsTab, setActiveSettingsTab] = useState('supabase');
    const [supabaseConfig, setSupabaseConfig] = useState<SupabaseConfig>({
        enabled: false,
        url: '',
        key: ''
    });
    const [customApiConfig, setCustomApiConfig] = useState<CustomApiConfig>({
        endpoints: []
    });

    // Voice & Saving State
    const [isListening, setIsListening] = useState(false);
    const [isSaving, setIsSaving] = useState(false);
    const [isChatOpen, setIsChatOpen] = useState(false);
    const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const recognitionRef = useRef<any>(null);
    const saveTimeoutRef = useRef<NodeJS.Timeout | null>(null);

    useEffect(() => {
        const fetchProject = async () => {
            try {
                const res = await fetch(`/api/projects/${projectId}`);
                if (res.ok) {
                    const data = await res.json();
                    setProjectName(data.project.name);
                    if (data.project.canvasData) {
                        setInitialCanvasData(JSON.parse(data.project.canvasData));
                    }
                    if (data.project.supabaseConfig) {
                        setSupabaseConfig(JSON.parse(data.project.supabaseConfig) as SupabaseConfig);
                    }
                    if (data.project.customApiConfig) {
                        setCustomApiConfig(JSON.parse(data.project.customApiConfig) as CustomApiConfig);
                    }
                }
            } catch (err) {
                console.error('Failed to fetch project:', err);
            } finally {
                setIsLoading(false);
            }
        };
        fetchProject();
    }, [projectId]);

    const handleSave = async (autoData?: unknown) => {
        setIsSaving(true);
        const canvasData = autoData || canvasRef.current?.getCanvasData();
        if (!canvasData) {
            setIsSaving(false);
            return;
        }

        try {
            await fetch(`/api/projects/${projectId}`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    canvasData: JSON.stringify(canvasData),
                    supabaseConfig: JSON.stringify(supabaseConfig),
                    customApiConfig: JSON.stringify(customApiConfig)
                })
            });

            if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);
            saveTimeoutRef.current = setTimeout(() => setIsSaving(false), 2000);
        } catch (err) {
            console.error('Failed to save content:', err);
            setIsSaving(false);
        }
    };

    const handleGenerate = async () => {
        if (!prompt.trim()) return;
        setIsGenerating(true);

        let selectedShapes = null;
        try {
            selectedShapes = canvasRef.current?.getSelectedShapes() || null;
        } catch (e) {
            console.error("Error capturing canvas selection:", e);
        }

        try {
            const payload = {
                projectId,
                prompt,
                framework,
                language,
                canvasData: selectedShapes,
                supabaseConfig: supabaseConfig.enabled ? supabaseConfig : null,
                customApiConfig: customApiConfig.endpoints.length > 0 ? customApiConfig : null
            };

            const res = await fetch('/api/generate', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload)
            });

            if (!res.ok) throw new Error("Generation request failed");

            const data = await res.json();
            if (data.success) {
                canvasRef.current?.addPreviewShape(data.code.code, data.code.id);
                setPrompt(''); // Clear prompt on success
            }
        } catch (err) {
            console.error("Generation error:", err);
            alert("Failed to generate UI. Please check console or try a different prompt.");
        } finally {
            setIsGenerating(false);
        }
    };

    const handleChatMessage = async (message: string) => {
        const userMsg: ChatMessage = { id: Date.now().toString(), role: 'user', content: message, timestamp: new Date() };
        setChatMessages(prev => [...prev, userMsg]);

        setIsGenerating(true);
        try {
            const shapes = canvasRef.current?.getSelectedShapes();
            const res = await fetch('/api/generate', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    projectId,
                    prompt: message,
                    canvasData: shapes,
                    language,
                    framework,
                    supabaseConfig: supabaseConfig.enabled ? supabaseConfig : null,
                    customApiConfig: customApiConfig.endpoints.length > 0 ? customApiConfig : null
                })
            });

            if (!res.ok) throw new Error("Failed to generate code via chat");

            const data = await res.json();
            if (data.success) {
                canvasRef.current?.addPreviewShape(data.code.code, data.code.id);
                const assistantMsg: ChatMessage = {
                    id: (Date.now() + 1).toString(),
                    role: 'assistant',
                    content: "Applied the requested changes! You can find the updated preview on your canvas.",
                    timestamp: new Date()
                };
                setChatMessages(prev => [...prev, assistantMsg]);
            }
        } catch (err) {
            console.error("Chat error:", err);
            const errorMsg: ChatMessage = {
                id: (Date.now() + 1).toString(),
                role: 'assistant',
                content: "I'm having trouble processing that right now. Could you try rephrasing?",
                timestamp: new Date()
            };
            setChatMessages(prev => [...prev, errorMsg]);
        } finally {
            setIsGenerating(false);
        }
    };

    return (
        <div className="flex h-screen bg-background text-foreground overflow-hidden selection:bg-primary/20">
            {/* Left Sidebar - Navigation & Primary Tools */}
            <div className="w-16 bg-card border-r border-border flex flex-col items-center py-6 gap-6 z-50 shadow-xl">
                <button
                    onClick={() => router.push('/dashboard')}
                    className="w-10 h-10 rounded-xl bg-background border border-border flex items-center justify-center hover:bg-accent transition-all active:scale-90"
                    title="Back to Dashboard"
                >
                    <ChevronLeft className="w-5 h-5" />
                </button>
                <div className="w-8 h-px bg-border" />
                <button className="p-2.5 rounded-xl bg-primary text-primary-foreground shadow-lg shadow-primary/20">
                    <Layout className="w-6 h-6" />
                </button>
                <button
                    onClick={() => setIsChatOpen(!isChatOpen)}
                    className={cn(
                        "p-2.5 rounded-xl transition-all relative group",
                        isChatOpen
                            ? "bg-primary/10 text-primary"
                            : "text-muted-foreground hover:bg-accent hover:text-foreground"
                    )}
                    title="AI Assistant"
                >
                    <MessageSquare className="w-6 h-6" />
                    {!isChatOpen && <div className="absolute right-0 top-0 w-2 h-2 bg-primary rounded-full border-2 border-card" />}
                    <div className="absolute left-14 px-2 py-1 bg-popover text-popover-foreground text-[10px] font-bold rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none">
                        Chat Assistant
                    </div>
                </button>
                <div className="mt-auto flex flex-col items-center gap-4">
                    <button
                        onClick={() => setShowSettings(true)}
                        className={cn(
                            "p-2.5 rounded-xl transition-all",
                            showSettings ? "bg-primary/10 text-primary" : "text-muted-foreground hover:bg-accent hover:text-foreground"
                        )}
                        title="Integrations & Settings"
                    >
                        <Settings className="w-6 h-6" />
                    </button>
                    <div className="w-10 h-10 rounded-full bg-muted border border-border flex items-center justify-center text-[10px] font-bold">
                        {projectName.substring(0, 2).toUpperCase()}
                    </div>
                </div>
            </div>

            {/* Main Canvas Area */}
            <div className="flex-1 relative overflow-hidden bg-[radial-gradient(circle_at_center,var(--border)_1px,transparent_1px)] bg-[size:24px_24px]">
                {isLoading ? (
                    <div className="absolute inset-0 z-50 flex items-center justify-center bg-background/80 backdrop-blur-sm">
                        <div className="flex flex-col items-center gap-6">
                            <div className="relative">
                                <div className="w-16 h-16 border-4 border-primary/10 border-t-primary rounded-full animate-spin" />
                                <div className="absolute inset-0 flex items-center justify-center">
                                    <div className="w-8 h-8 bg-primary/20 rounded-full animate-pulse" />
                                </div>
                            </div>
                            <div className="text-center">
                                <h3 className="text-lg font-bold italic-title">Initializing Workspace</h3>
                                <p className="text-xs text-muted-foreground uppercase tracking-widest mt-1">Fetching Canvas States</p>
                            </div>
                        </div>
                    </div>
                ) : (
                    <CanvasBoard
                        ref={canvasRef}
                        onSave={handleSave}
                        initialData={initialCanvasData}
                    />
                )}

                <ChatSidebar
                    isOpen={isChatOpen}
                    onClose={() => setIsChatOpen(false)}
                    onSendMessage={handleChatMessage}
                    isGenerating={isGenerating}
                    messages={chatMessages}
                />

                {/* Top Center Toolbar */}
                <div className="absolute top-6 left-1/2 -translate-x-1/2 bg-card/90 backdrop-blur-xl px-4 py-2.5 rounded-2xl shadow-2xl border border-border/50 flex items-center gap-4 z-40 transition-all hover:border-primary/30">
                    <div className="flex items-center gap-3">
                        <h2 className="text-sm font-bold tracking-tight px-2">{projectName}</h2>
                        <div
                            className={cn(
                                "flex items-center gap-1.5 px-2 py-0.5 rounded-full text-[9px] font-black uppercase tracking-tighter",
                                isSaving ? "bg-amber-500/10 text-amber-600 animate-pulse" : "bg-emerald-500/10 text-emerald-600"
                            )}
                        >
                            <span className={cn("w-1.5 h-1.5 rounded-full", isSaving ? "bg-amber-500" : "bg-emerald-500")} />
                            {isSaving ? "Saving" : "Synced"}
                        </div>
                    </div>
                    <div className="w-px h-6 bg-border" />
                    <div className="flex items-center gap-1">
                        <button
                            className="p-1.5 hover:bg-accent rounded-lg text-muted-foreground transition-all active:scale-90"
                            title="Undo"
                            onClick={() => (canvasRef.current as any)?.getEditor()?.undo()}
                        >
                            <Undo2 className="w-4 h-4" />
                        </button>
                        <button
                            className="p-1.5 hover:bg-accent rounded-lg text-muted-foreground transition-all active:scale-90"
                            title="Redo"
                            onClick={() => (canvasRef.current as any)?.getEditor()?.redo()}
                        >
                            <Redo2 className="w-4 h-4" />
                        </button>
                    </div>
                    <div className="w-px h-6 bg-border" />
                    <button
                        onClick={() => handleSave()}
                        disabled={isSaving}
                        className="flex items-center gap-2 pl-2 pr-1 text-xs font-bold text-primary hover:text-primary/80 transition-colors disabled:opacity-50"
                    >
                        Force Save
                        <div className="p-1.5 bg-primary/10 rounded-lg group-hover:bg-primary/20 transition-colors">
                            <Save className="w-4 h-4" />
                        </div>
                    </button>
                </div>

                {/* Bottom Center Engine Bar */}
                <div className="absolute bottom-8 left-1/2 -translate-x-1/2 w-full max-w-3xl px-8 z-40">
                    <div className="flex flex-col gap-4">
                        {/* Configuration Strip */}
                        <div className="flex items-center justify-between bg-card/80 backdrop-blur-xl px-4 py-2 rounded-2xl border border-border/50 shadow-xl overflow-x-auto no-scrollbar">
                            <div className="flex items-center gap-6">
                                <div className="flex items-center gap-3">
                                    <span className="text-[10px] font-black text-muted-foreground uppercase opacity-60">Framework</span>
                                    <div className="flex items-center bg-muted rounded-xl p-1">
                                        {['react', 'nextjs'].map((f) => (
                                            <button
                                                key={f}
                                                onClick={() => setFramework(f)}
                                                className={cn(
                                                    "px-4 py-1.5 text-[11px] font-bold rounded-lg transition-all capitalize",
                                                    framework === f ? "bg-card text-primary shadow-sm" : "text-muted-foreground hover:text-foreground"
                                                )}
                                            >
                                                {f}
                                            </button>
                                        ))}
                                    </div>
                                </div>
                                <div className="h-4 w-px bg-border" />
                                <div className="flex items-center gap-3">
                                    <span className="text-[10px] font-black text-muted-foreground uppercase opacity-60">Language</span>
                                    <div className="flex items-center bg-muted rounded-xl p-1">
                                        {['typescript', 'javascript'].map((l) => (
                                            <button
                                                key={l}
                                                onClick={() => setLanguage(l)}
                                                className={cn(
                                                    "px-4 py-1.5 text-[11px] font-bold rounded-lg transition-all capitalize",
                                                    language === l ? "bg-card text-primary shadow-sm" : "text-muted-foreground hover:text-foreground"
                                                )}
                                            >
                                                {l === 'typescript' ? 'TS' : 'JS'}
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            </div>
                            <div className="flex items-center gap-4 ml-4">
                                <div className="h-4 w-px bg-border" />
                                <p className="text-[10px] font-bold text-muted-foreground bg-accent px-2 py-1 rounded">V4 ENGINE</p>
                            </div>
                        </div>

                        {/* Main AI Terminal */}
                        <div className="bg-card/95 backdrop-blur-2xl p-2 rounded-3xl shadow-2xl border border-border/40 focus-within:border-primary/40 focus-within:ring-4 focus-within:ring-primary/5 transition-all">
                            <div className="relative flex items-center">
                                <textarea
                                    value={prompt}
                                    onChange={(e) => setPrompt(e.target.value)}
                                    placeholder="Describe your vision, and AI will weave the code..."
                                    className="w-full bg-transparent border-none focus:ring-0 text-sm font-medium py-4 px-6 pr-36 min-h-[60px] max-h-[200px] resize-none text-foreground placeholder:text-muted-foreground/50 scrollbar-none"
                                    rows={1}
                                    onKeyDown={(e) => {
                                        if (e.key === 'Enter' && !e.shiftKey) {
                                            e.preventDefault();
                                            handleGenerate();
                                        }
                                    }}
                                />
                                <div className="absolute right-3 flex items-center gap-3">
                                    <button
                                        onClick={() => {
                                            if (isListening) {
                                                recognitionRef.current?.stop();
                                                setIsListening(false);
                                                return;
                                            }

                                            // eslint-disable-next-line @typescript-eslint/ban-ts-comment
                                            // @ts-expect-error
                                            const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
                                            if (!SpeechRecognition) {
                                                alert('Speech recognition not supported in this browser.');
                                                return;
                                            }

                                            setIsListening(true);
                                            const recognition = new SpeechRecognition();
                                            recognitionRef.current = recognition;
                                            recognition.lang = 'en-US';
                                            recognition.continuous = true;
                                            recognition.interimResults = true;

                                            // eslint-disable-next-line @typescript-eslint/no-explicit-any
                                            recognition.onresult = (event: any) => {
                                                let finalTranscript = '';
                                                for (let i = event.resultIndex; i < event.results.length; ++i) {
                                                    if (event.results[i].isFinal) {
                                                        finalTranscript += event.results[i][0].transcript;
                                                    }
                                                }
                                                if (finalTranscript) {
                                                    setPrompt((prev) => prev + (prev ? ' ' : '') + finalTranscript);
                                                }
                                            };

                                            // eslint-disable-next-line @typescript-eslint/no-explicit-any
                                            recognition.onerror = (event: any) => {
                                                console.error('Speech recognition error:', event.error);
                                                setIsListening(false);
                                            };

                                            recognition.onend = () => {
                                                // Only stop if we manually set isListening to false
                                                if (isListening) {
                                                    try {
                                                        recognition.start();
                                                    } catch (e) {
                                                        setIsListening(false);
                                                    }
                                                }
                                            };

                                            recognition.start();
                                        }}
